  "query": "WITH sys AS (\n  SELECT timestamp, SUM(load_mw) AS ercot_load_mw\n  FROM ercot_load\n  WHERE is_day_ahead=false\n    AND timestamp >= '2024-06-01' AND timestamp < '2024-10-01'\n  GROUP BY timestamp\n), ranked AS (\n  SELECT *, EXTRACT(MONTH FROM timestamp)::int AS month,\n         ROW_NUMBER() OVER (PARTITION BY EXTRACT(MONTH FROM timestamp)::int ORDER BY ercot_load_mw DESC, timestamp) AS rn\n  FROM sys\n)\nSELECT month, timestamp, ercot_load_mw, EXTRACT(HOUR FROM timestamp)::int AS hour\nFROM ranked\nWHERE rn=1\nORDER BY month",
  "columns": [
    "month",
    "timestamp",
